                numEmpty++;
            i++;
        }
        t.end();
        UI.printDetailed(Module.ACCEL, "Uniform grid statistics:");
        UI.printDetailed(Module.ACCEL, "  * Grid cells:          %d", cells.length);
        UI.printDetailed(Module.ACCEL, "  * Used cells:          %d", cells.length - numEmpty);
